/**
 * @param {number} n
 * @param {number} m
 * @param {number[][]} sources
 * @return {number[][]}
 */
function solve(n, m, sources) {
    // This problem is a multi-source shortest path problem where the "cost" is the time taken,
    // and the value associated with reaching a cell is its color.
    // We want to find, for each cell, the color that arrives in the minimum time,
    // and if there's a tie in time, the color with the maximum value.

    // Since all edge weights are 1 (one time unit per move), a multi-source BFS is appropriate.
    // The state in the queue will be [r, c, time, color].

    // Initialize the grid to store the best arrival information:
    // grid[r][c] = { time: Infinity, color: 0 }
    const grid = Array(n).fill(0).map(() => Array(m).fill(0).map(() => ({
        time: Infinity,
        color: 0
    })));

    // Initialize the queue for BFS
    const queue = [];

    for (const [r, c, color] of sources) {
        const initialTime = 0;
        grid[r][c] = { time: 0, color: color };
        // Queue stores: [row, col, time, color]
        queue.push([r, c, initialTime, color]);
    }

    const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

    let head = 0;
    while (head < queue.length) {
        const [r, c, time, color] = queue[head++];
        const nextTime = time + 1;

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            // Check boundaries
            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const currentBest = grid[nr][nc];

                // Check if this new path (time, color) is better than the current best for (nr, nc)
                let isBetter = false;

                // 1. If the new time is strictly smaller
                if (nextTime < currentBest.time) {
                    isBetter = true;
                } 
                // 2. If the new time is equal, check the color (prefer maximum color)
                else if (nextTime === currentBest.time) {
                    if (color > currentBest.color) {
                        isBetter = true;
                    }
                }

                if (isBetter) {
                    // Update the grid state
                    grid[nr][nc] = { time: nextTime, color: color };
                    // Enqueue for further exploration
                    queue.push([nr, nc, nextTime, color]);
                }
            }
        }
    }

    // Format the result as a 2D array of colors
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = grid[r][c].color;
        }
    }

    return result;
}

